method ParsePositiveInt(s: string) returns (result: int, ok: bool)
  ensures ok ==> result > 0
{
  result := 0;
  ok := false;
  if |s| == 0 {
    return;
  }
  var i := 0;
  var acc := 0;
  while i < |s|
    invariant 0 <= i <= |s|
    invariant acc >= 0
  {
    var c := s[i];
    if c < '0' || c > '9' {
      return;
    }
    acc := acc * 10 + (c as int - '0' as int);
    i := i + 1;
  }
  if acc > 0 {
    result := acc;
    ok := true;
  }
}

